        isEditMode={true}
        {...props}
    />
);

const InUse = (props: Story) => {
	const [data, setData] = useState('this is a default value');
	const [error, setError] = useState(false);
	const [loading, setLoading] = useState(false);
	const onCancel = () => {
		setError(false);
	};
	const onEdit = () => {
		setError(false);
		setLoading(true);
		setTimeout(() => {
			setLoading(false);
			setData(data);
			setError(true);
		}, 2000);
	};

	return (
		<>
			<InlineEditing.Text
				placeholder="Input a crawler name"
				label="Crawler name"
				loading={loading}
				defaultValue={data}
				hasError={error}
				onToggle={action('onToggle')}
				onEdit={onEdit}
				onCancel={onCancel}
				aria-describedby="inlinemessage-id"
				description={error ? 'An error occurred' : undefined}
				{...props}
			/>
		</>
	);
};

