const ToggleSwitchReactHooksForm = () => {
	const { register, handleSubmit, watch } = useForm<Inputs>();
	const [formData, setFormData] = useState<null | Inputs>();
	const watchAllFields = watch();

	return (
		<Form onSubmit={handleSubmit(setFormData)}>
			{formData && (
				<InlineMessageInformation
					title={'Form data'}
					description={JSON.stringify(formData, null, 2)}
					withBackground
				/>
			)}
			<Form.Fieldset legend="Enabled">
				<Form.ToggleSwitch
					label="Option a"
					{...register('option-a')}
					checked={watchAllFields['option-a']}
				/>
				<Form.ToggleSwitch
					label="Option b"
					defaultChecked
					{...register('option-b')}
					checked={watchAllFields['option-b']}
				/>
			</Form.Fieldset>
			<Form.Fieldset legend="Read only" readOnly>
				<Form.ToggleSwitch
					label="Option c"
					{...register('option-c')}
					checked={watchAllFields['option-c']}
				/>
				<Form.ToggleSwitch
					label="Option d"
					defaultChecked
					{...register('option-d')}
					checked={watchAllFields['option-d']}
				/>
			</Form.Fieldset>
			<Form.Fieldset legend="Disabled" disabled>
				<Form.ToggleSwitch
					label="Option e"
					disabled
					{...register('option-e')}
					checked={watchAllFields['option-e']}
				/>
				<Form.ToggleSwitch
					label="Option f"
					defaultChecked
					disabled
					{...register('option-f')}
					checked={watchAllFields['option-f']}
				/>
			</Form.Fieldset>
			<Form.Buttons>
				<ButtonPrimary onClick={() => {}} type="submit">
					Submit
				</ButtonPrimary>
			</Form.Buttons>
		</Form>
	);
};

